```class Solution {
public:
    int countSegments(string s) {
        if (s.empty() || s[0] == ' ') return 0;
        int count = 1;
        for (int i = 1; i < s.size(); i++) {
            if (s[i] == ' ' && s[i - 1] != ' ') count++;
        }
        return count;
    }
};```
